    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {
        //         "coin": "BTC",
        //         "address": "1BfZh7JESJGBUszCGeZnzxbVVvBycbJSbA",
        //         "chain": "",
        //         "tag": null,
        //         "url": "https://blockchair.com/bitcoin/transaction/"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(depositAddress, "coin");
        Object networkId = this.safeString(depositAddress, "chain");
        Object parsedCurrency = this.safeCurrencyCode(currencyId, currency);
        Object network = null;
        if (Helpers.isTrue(!Helpers.isEqual(networkId, null)))
        {
            network = this.networkIdToCode(networkId, parsedCurrency);
        }
        final Object finalNetwork = network;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", parsedCurrency );
            put( "network", finalNetwork );
            put( "address", BitgetCore.this.safeString(depositAddress, "address") );
            put( "tag", BitgetCore.this.safeString(depositAddress, "tag") );
        }};
    }

    /**
     * @method
     * @name bitget#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://www.bitget.com/api-doc/spot/market/Get-Orderbook
     * @see https://www.bitget.com/api-doc/contract/market/Get-Merge-Depth
     * @see https://www.bitget.com/api-doc/uta/public/OrderBook
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.uta] set to true for the unified trading account (uta), defaults to false
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object productType = null;
            var productTypeparametersVariable = this.handleProductTypeAndParams(market, parameters);
            productType = ((java.util.List<Object>) productTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) productTypeparametersVariable).get(1);
            Object response = null;
            Object uta = null;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchOrderBook", "uta", false);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            if (Helpers.isTrue(uta))
            {
                Helpers.addElementToObject(request, "category", productType);
                response = (this.publicUtaGetV3MarketOrderbook(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                response = (this.publicSpotGetV2SpotMarketOrderbook(this.extend(request, parameters))).join();
            } else
            {
                Helpers.addElementToObject(request, "productType", productType);
                response = (this.publicMixGetV2MixMarketMergeDepth(this.extend(request, parameters))).join();
            }
            //
            //     {
            //       "code": "00000",
            //       "msg": "success",
            //       "requestTime": 1645854610294,
            //       "data": {
            //         "asks": [ [ "39102", "11.026" ] ],
            //         "bids": [ [ '39100.5', "1.773" ] ],
            //         "ts": "1645854610294"
            //       }
            //     }
            //
            // uta
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1750329437753,
            //         "data": {
            //             "a": [ [ 104992.60, 0.018411 ] ],
            //             "b":[ [104927.40, 0.229914 ] ],
            //             "ts": "1750329437763"
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object bidsKey = ((Helpers.isTrue(uta))) ? "b" : "bids";
            Object asksKey = ((Helpers.isTrue(uta))) ? "a" : "asks";
            Object timestamp = this.safeInteger(data, "ts");
            return this.parseOrderBook(data, Helpers.GetValue(market, "symbol"), timestamp, bidsKey, asksKey);
        });

    }

