    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // spot
        //
        //     {
        //         "billId": "1111506298997215233",
        //         "coin": "USDT",
        //         "groupType": "transfer",
        //         "businessType": "transfer_out",
        //         "size": "-11.64958799",
        //         "balance": "0.00000000",
        //         "fees": "0.00000000",
        //         "cTime": "1700729673028"
        //     }
        //
        // swap and future
        //
        //     {
        //         "billId": "1111499428100472833",
        //         "symbol": "",
        //         "amount": "-11.64958799",
        //         "fee": "0",
        //         "feeByCoupon": "",
        //         "businessType": "trans_to_exchange",
        //         "coin": "USDT",
        //         "cTime": "1700728034996"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(item, "coin");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object timestamp = this.safeInteger(item, "cTime");
        Object after = this.safeNumber(item, "balance");
        Object fee = this.safeNumber2(item, "fees", "fee");
        Object amountRaw = this.safeString2(item, "size", "amount");
        Object amount = this.parseNumber(Precise.stringAbs(amountRaw));
        Object direction = "in";
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(amountRaw, "-"), 0)))
        {
            direction = "out";
        }
        final Object finalDirection = direction;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", BitgetCore.this.safeString(item, "billId") );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
            put( "direction", finalDirection );
            put( "account", null );
            put( "referenceId", null );
            put( "referenceAccount", null );
            put( "type", BitgetCore.this.parseLedgerType(BitgetCore.this.safeString(item, "businessType")) );
            put( "currency", code );
            put( "amount", amount );
            put( "before", null );
            put( "after", after );
            put( "status", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", fee );
            }} );
        }}, currency);
    }

