            //                 },
            //                 "tradeScope": "taker",
            //                 "cTime": "1697603539699",
            //                 "uTime": "1697603539754"
            //             }
            //         ]
            //     }
            //
            // spot margin
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1700803176399,
            //         "data": {
            //             "fills": [
            //                 {
            //                     "orderId": "1099353730455318528",
            //                     "tradeId": "1099353730627092481",
            //                     "orderType": "market",
            //                     "side": "sell",
            //                     "priceAvg": "29543.7",
            //                     "size": "0.0001",
            //                     "amount": "2.95437",
            //                     "tradeScope": "taker",
            //                     "feeDetail": {
            //                         "deduction": "no",
            //                         "feeCoin": "USDT",
            //                         "totalDeductionFee": "0",
            //                         "totalFee": "-0.00295437"
            //                     },
            //                     "cTime": "1697832275063",
            //                     "uTime": "1697832275150"
            //                 },
            //             ],
            //             "minId": "1099353591699161118",
            //             "maxId": "1099353730627092481"
            //         }
            //     }
            //
            // swap and future
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1700803357487,
            //         "data": {
            //             "fillList": [
            //                 {
            //                     "tradeId": "1111468664328269825",
            //                     "symbol": "BTCUSDT",
            //                     "orderId": "1111468664264753162",
            //                     "price": "37271.4",
            //                     "baseVolume": "0.001",
            //                     "feeDetail": [
            //                         {
            //                             "deduction": "no",
            //                             "feeCoin": "USDT",
            //                             "totalDeductionFee": null,
            //                             "totalFee": "-0.02236284"
            //                         }
            //                     ],
            //                     "side": "buy",
            //                     "quoteVolume": "37.2714",
            //                     "profit": "-0.0007",
            //                     "enterPointSource": "web",
