    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        // fetchFundingRate: publicMixGetV2MixMarketCurrentFundRate, publicUtaGetV3MarketCurrentFundRate
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "fundingRate": "-0.000013",
        //         "fundingRateInterval": "8",
        //         "nextUpdate": "1745510400000",
        //         "minFundingRate": "-0.003",
        //         "maxFundingRate": "0.003"
        //     }
        //
        // fetchFundingRate: publicMixGetV2MixMarketFundingTime
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "nextFundingTime": "1745424000000",
        //         "ratePeriod": "8"
        //     }
        //
        // fetchFundingInterval
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "nextFundingTime": "1727942400000",
        //         "ratePeriod": "8"
        //     }
        //
        // fetchFundingRates
        //
        //     {
        //         "symbol": "BTCUSD",
        //         "lastPr": "29904.5",
        //         "askPr": "29904.5",
        //         "bidPr": "29903.5",
        //         "bidSz": "0.5091",
        //         "askSz": "2.2694",
        //         "high24h": "0",
        //         "low24h": "0",
        //         "ts": "1695794271400",
        //         "change24h": "0",
        //         "baseVolume": "0",
        //         "quoteVolume": "0",
        //         "usdtVolume": "0",
        //         "openUtc": "0",
        //         "changeUtc24h": "0",
        //         "indexPrice": "29132.353333",
        //         "fundingRate": "-0.0007",
        //         "holdingAmount": "125.6844",
        //         "deliveryStartTime": null,
        //         "deliveryTime": null,
        //         "deliveryStatus": "delivery_normal",
        //         "open24h": "0",
        //         "markPrice": "12345"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(contract, "symbol");
        Object symbol = this.safeSymbol(marketId, market, null, "swap");
        Object fundingTimestamp = this.safeInteger2(contract, "nextFundingTime", "nextUpdate");
        Object interval = this.safeString2(contract, "ratePeriod", "fundingRateInterval");
        Object timestamp = this.safeInteger(contract, "ts");
        Object markPrice = this.safeNumber(contract, "markPrice");
        Object indexPrice = this.safeNumber(contract, "indexPrice");
        Object intervalString = null;
        if (Helpers.isTrue(!Helpers.isEqual(interval, null)))
        {
            intervalString = Helpers.add(interval, "h");
        }
        final Object finalIntervalString = intervalString;
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", symbol );
            put( "markPrice", markPrice );
            put( "indexPrice", indexPrice );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
            put( "fundingRate", BitgetCore.this.safeNumber(contract, "fundingRate") );
            put( "fundingTimestamp", fundingTimestamp );
            put( "fundingDatetime", BitgetCore.this.iso8601(fundingTimestamp) );
            put( "nextFundingRate", null );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", finalIntervalString );
        }};
    }

    /**
     * @method
     * @name bitget#fetchFundingHistory
     * @description fetch the funding history
     * @see https://www.bitget.com/api-doc/contract/account/Get-Account-Bill
     * @param {string} symbol unified market symbol
     * @param {int} [since] the starting timestamp in milliseconds
     * @param {int} [limit] the number of entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch funding history for
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {object[]} a list of [funding history structures]{@link https://docs.ccxt.com/?id=funding-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchFundingHistory() requires a symbol argument")) ;
            }
            Object uta = null;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchFundingHistory", "uta", false);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchFundingHistory", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                if (Helpers.isTrue(uta))
                {
                    return (this.fetchPaginatedCallCursor("fetchFundingHistory", symbol, since, limit, parameters, "cursor", "cursor")).join();
                }
                return (this.fetchPaginatedCallCursor("fetchFundingHistory", symbol, since, limit, parameters, "endId", "idLessThan")).join();
            }
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new BadSymbol((String)Helpers.add(this.id, " fetchFundingHistory() supports swap contracts only")) ;
            }
            Object productType = null;
            var productTypeparametersVariable = this.handleProductTypeAndParams(market, parameters);
            productType = ((java.util.List<Object>) productTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) productTypeparametersVariable).get(1);
            Object request = new java.util.HashMap<String, Object>() {{}};
            var requestparametersVariable = this.handleUntilOption("endTime", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = null;
            if (Helpers.isTrue(uta))
            {
                Helpers.addElementToObject(request, "coin", Helpers.GetValue(market, "settleId"));
                Helpers.addElementToObject(request, "category", productType);
                response = (this.privateUtaGetV3AccountFinancialRecords(this.extend(request, parameters))).join();
            } else
            {
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
                Helpers.addElementToObject(request, "marginCoin", Helpers.GetValue(market, "settleId"));
                Helpers.addElementToObject(request, "businessType", "contract_settle_fee");
                Helpers.addElementToObject(request, "productType", productType);
                response = (this.privateMixGetV2MixAccountBill(this.extend(request, parameters))).join();
            }
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object bills = this.safeList2(data, "bills", "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            if (Helpers.isTrue(uta))
            {
                bills = this.filterByArray(bills, "type", new java.util.ArrayList<Object>(java.util.Arrays.asList("CONTRACT_MAIN_SETTLE_FEE_USER_IN", "CONTRACT_MAIN_SETTLE_FEE_USER_OUT")), false);
            }
            return this.parseFundingHistories(bills, market, since, limit);
        });

    }

    public Object parseFundingHistory(Object contract, Object... optionalArgs)
    {
        //
        //     {
        //         "billId": "1111499428100472833",
        //         "symbol": "BTCUSDT",
        //         "amount": "-0.004992",
        //         "fee": "0",
        //         "feeByCoupon": "",
        //         "businessType": "contract_settle_fee",
        //         "coin": "USDT",
        //         "cTime": "1700728034996"
        //     }
        //
        //     {
        //         "category": "Margin",
        //         "id": "13111111111111111",
        //         "symbol": "BTCUSDT",
        //         "coin": "BTC",
        //         "type": "ORDER_DEALT_IN",
        //         "amount": "0.00531168",
        //         "fee": "-0.00000531",
        //         "balance": "55.10017801",
        //         "ts": "1745853486185"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(contract, "symbol");
        Object currencyId = this.safeString(contract, "coin");
        Object timestamp = this.safeInteger2(contract, "cTime", "ts");
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", BitgetCore.this.safeSymbol(marketId, market, null, "swap") );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
            put( "code", BitgetCore.this.safeCurrencyCode(currencyId) );
            put( "amount", BitgetCore.this.safeNumber(contract, "amount") );
            put( "id", BitgetCore.this.safeString2(contract, "billId", "id") );
        }};
    }

    public Object parseFundingHistories(Object contracts, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object since = Helpers.getArg(optionalArgs, 1, null);
        Object limit = Helpers.getArg(optionalArgs, 2, null);
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(contracts)); i++)
        {
            Object contract = Helpers.GetValue(contracts, i);
            // for non-uta, we've set bussinessType in request payload. Not sure why this existed.
            // const business = this.safeString (contract, 'businessType');
            // if (business !== 'contract_settle_fee') {
            //     continue;
            // }
            ((java.util.List<Object>)result).add(this.parseFundingHistory(contract, market));
        }
        Object sorted = this.sortBy(result, "timestamp");
        Object symbol = null;
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            symbol = Helpers.GetValue(market, "symbol");
        }
        return this.filterBySymbolSinceLimit(sorted, symbol, since, limit);
    }

    public java.util.concurrent.CompletableFuture<Object> modifyMarginHelper(Object symbol, Object amount, Object type, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object holdSide = this.safeString(parameters, "holdSide");
            Object market = this.market(symbol);
            Object productType = null;
            var productTypeparametersVariable = this.handleProductTypeAndParams(market, parameters);
            productType = ((java.util.List<Object>) productTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) productTypeparametersVariable).get(1);
            final Object finalProductType = productType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "marginCoin", Helpers.GetValue(market, "settleId") );
                put( "amount", BitgetCore.this.amountToPrecision(symbol, amount) );
                put( "holdSide", holdSide );
                put( "productType", finalProductType );
            }};
            parameters = this.omit(parameters, "holdSide");
            Object response = (this.privateMixPostV2MixAccountSetMargin(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1700813444618,
            //         "data": ""
            //     }
            //
            return this.extend(this.parseMarginModification(response, market), new java.util.HashMap<String, Object>() {{
                put( "amount", BitgetCore.this.parseNumber(amount) );
                put( "type", type );
            }});
        });

    }

    public Object parseMarginModification(Object data, Object... optionalArgs)
    {
        //
        // addMargin/reduceMargin
        //
        //     {
        //         "code": "00000",
        //         "msg": "success",
        //         "requestTime": 1700813444618,
        //         "data": ""
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object errorCode = this.safeString(data, "code");
        Object status = ((Helpers.isTrue((Helpers.isEqual(errorCode, "00000"))))) ? "ok" : "failed";
        return new java.util.HashMap<String, Object>() {{
            put( "info", data );
            put( "symbol", BitgetCore.this.safeString(market, "symbol") );
            put( "type", null );
            put( "marginMode", "isolated" );
            put( "amount", null );
            put( "total", null );
            put( "code", BitgetCore.this.safeString(market, "settle") );
            put( "status", status );
            put( "timestamp", null );
            put( "datetime", null );
        }};
    }

