    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // transfer
        //
        //     {
        //         "transferId": "1112112916581847040",
        //         "clientOrderId": null,
        //         "ts": 1700874302021
        //     }
        //
        // fetchTransfers
        //
        //     {
        //         "coin": "USDT",
        //         "status": "Successful",
        //         "toType": "crossed_margin",
        //         "toSymbol": "",
        //         "fromType": "spot",
        //         "fromSymbol": "",
        //         "size": "11.64958799",
        //         "ts": "1700729673028",
        //         "clientOid": "1111506298504744960",
        //         "transferId": "24930940"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transfer, "ts");
        Object status = this.safeStringLower(transfer, "status");
        Object currencyId = this.safeString(transfer, "coin");
        Object fromAccountRaw = this.safeString(transfer, "fromType");
        Object accountsById = this.safeValue(this.options, "accountsById", new java.util.HashMap<String, Object>() {{}});
        Object fromAccount = this.safeString(accountsById, fromAccountRaw, fromAccountRaw);
        Object toAccountRaw = this.safeString(transfer, "toType");
        Object toAccount = this.safeString(accountsById, toAccountRaw, toAccountRaw);
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", BitgetCore.this.safeString(transfer, "transferId") );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
            put( "currency", BitgetCore.this.safeCurrencyCode(currencyId, currency) );
            put( "amount", BitgetCore.this.safeNumber(transfer, "size") );
            put( "fromAccount", fromAccount );
            put( "toAccount", toAccount );
            put( "status", BitgetCore.this.parseTransferStatus(status) );
        }};
    }

    public Object parseTransferStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "successful", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        //     {
        //         "chains": [
        //             {
        //                 "browserUrl": "https://blockchair.com/bitcoin/transaction/",
        //                 "chain": "BTC",
        //                 "depositConfirm": "1",
        //                 "extraWithdrawFee": "0",
        //                 "minDepositAmount": "0.0001",
        //                 "minWithdrawAmount": "0.005",
        //                 "needTag": "false",
        //                 "rechargeable": "true",
        //                 "withdrawConfirm": "1",
        //                 "withdrawFee": "0.0004",
        //                 "withdrawable": "true"
        //             },
        //         ],
        //         "coin": "BTC",
        //         "coinId": "1",
        //         "transfer": "true""
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object chains = this.safeValue(fee, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object chainsLength = Helpers.getArrayLength(chains);
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
        for (var i = 0; Helpers.isLessThan(i, chainsLength); i++)
        {
            Object chain = Helpers.GetValue(chains, i);
            Object networkId = this.safeString(chain, "chain");
            Object currencyCode = this.safeString(currency, "code");
            Object networkCode = this.networkIdToCode(networkId, currencyCode);
            Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", BitgetCore.this.safeNumber(chain, "withdrawFee") );
        put( "percentage", false );
    }} );
}});
            if (Helpers.isTrue(Helpers.isEqual(chainsLength, 1)))
            {
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "fee", this.safeNumber(chain, "withdrawFee"));
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "percentage", false);
            }
        }
        return result;
    }

