    public Object parseMarginLoan(Object info, Object... optionalArgs)
    {
        //
        // isolated: borrowMargin
        //
        //     {
        //         "loanId": "1112125304879067137",
        //         "symbol": "BTCUSDT",
        //         "coin": "USDT",
        //         "borrowAmount": "4"
        //     }
        //
        // cross: borrowMargin
        //
        //     {
        //         "loanId": "1112122013642272769",
        //         "coin": "USDT",
        //         "borrowAmount": "4"
        //     }
        //
        // isolated: repayMargin
        //
        //     {
        //         "remainDebtAmount": "0",
        //         "repayId": "1112126405439270912",
        //         "symbol": "BTCUSDT",
        //         "coin": "USDT",
        //         "repayAmount": "8.000137"
        //     }
        //
        // cross: repayMargin
        //
        //     {
        //         "remainDebtAmount": "0",
        //         "repayId": "1112122994945830912",
        //         "coin": "USDT",
        //         "repayAmount": "4.00006834"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object market = Helpers.getArg(optionalArgs, 1, null);
        Object currencyId = this.safeString(info, "coin");
        Object marketId = this.safeString(info, "symbol");
        Object symbol = null;
        if (Helpers.isTrue(!Helpers.isEqual(marketId, null)))
        {
            symbol = this.safeSymbol(marketId, market, null, "spot");
        }
        final Object finalSymbol = symbol;
        return new java.util.HashMap<String, Object>() {{
            put( "id", BitgetCore.this.safeString2(info, "loanId", "repayId") );
            put( "currency", BitgetCore.this.safeCurrencyCode(currencyId, currency) );
            put( "amount", BitgetCore.this.safeNumber2(info, "borrowAmount", "repayAmount") );
            put( "symbol", finalSymbol );
            put( "timestamp", null );
            put( "datetime", null );
            put( "info", info );
        }};
    }

    /**
     * @method
     * @name bitget#fetchMyLiquidations
     * @description retrieves the users liquidated positions
     * @see https://www.bitget.com/api-doc/margin/cross/record/Get-Cross-Liquidation-Records
     * @see https://www.bitget.com/api-doc/margin/isolated/record/Get-Isolated-Liquidation-Records
     * @param {string} [symbol] unified CCXT market symbol
     * @param {int} [since] the earliest time in ms to fetch liquidations for
     * @param {int} [limit] the maximum number of liquidation structures to retrieve
     * @param {object} [params] exchange specific parameters for the bitget api endpoint
     * @param {int} [params.until] timestamp in ms of the latest liquidation
     * @param {string} [params.marginMode] 'cross' or 'isolated' default value is 'cross'
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {object} an array of [liquidation structures]{@link https://docs.ccxt.com/?id=liquidation-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyLiquidations(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchMyLiquidations", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallCursor("fetchMyLiquidations", symbol, since, limit, parameters, "minId", "idLessThan")).join();
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
            }
            Object type = null;
            var typeparametersVariable = this.handleMarketTypeAndParams("fetchMyLiquidations", market, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(type, "spot")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchMyLiquidations() supports spot margin markets only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            var requestparametersVariable = this.handleUntilOption("endTime", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", since);
            } else
            {
                Helpers.addElementToObject(request, "startTime", Helpers.subtract(this.milliseconds(), 7776000000L));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = null;
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchMyLiquidations", parameters, "cross");
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
            {
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyLiquidations() requires a symbol argument")) ;
                }
                Helpers.addElementToObject(request, "symbol", this.safeString(market, "id"));
                response = (this.privateMarginGetV2MarginIsolatedLiquidationHistory(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marginMode, "cross")))
            {
                response = (this.privateMarginGetV2MarginCrossedLiquidationHistory(this.extend(request, parameters))).join();
            }
            //
            // isolated
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1698114119193,
            //         "data": {
            //             "resultList": [
            //                 {
            //                     "liqId": "123",
            //                     "symbol": "BTCUSDT",
            //                     "liqStartTime": "1653453245342",
            //                     "liqEndTime": "16312423423432",
            //                     "liqRiskRatio": "1.01",
            //                     "totalAssets": "1242.34",
            //                     "totalDebt": "1100",
            //                     "liqFee": "1.2",
            //                     "uTime": "1668134458717",
            //                     "cTime": "1653453245342"
            //                 }
            //             ],
            //             "maxId": "0",
            //             "minId": "0"
            //         }
            //     }
            //
            // cross
            //
            //     {
            //         "code": "00000",
            //         "msg": "success",
            //         "requestTime": 1698114119193,
            //         "data": {
            //             "resultList": [
            //                 {
            //                     "liqId": "123",
            //                     "liqStartTime": "1653453245342",
            //                     "liqEndTime": "16312423423432",
            //                     "liqRiskRatio": "1.01",
            //                     "totalAssets": "1242.34",
            //                     "totalDebt": "1100",
            //                     "LiqFee": "1.2",
            //                     "uTime": "1668134458717",
            //                     "cTime": "1653453245342"
            //                 }
            //             ],
            //             "maxId": "0",
            //             "minId": "0"
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object liquidations = this.safeList(data, "resultList", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseLiquidations(liquidations, market, since, limit);
        });

    }

    public Object parseLiquidation(Object liquidation, Object... optionalArgs)
    {
        //
        // isolated
        //
        //     {
        //         "liqId": "123",
        //         "symbol": "BTCUSDT",
        //         "liqStartTime": "1653453245342",
        //         "liqEndTime": "16312423423432",
        //         "liqRiskRatio": "1.01",
        //         "totalAssets": "1242.34",
        //         "totalDebt": "1100",
        //         "liqFee": "1.2",
        //         "uTime": "1692690126000"
        //         "cTime": "1653453245342"
        //     }
        //
        // cross
        //
        //     {
        //         "liqId": "123",
        //         "liqStartTime": "1653453245342",
        //         "liqEndTime": "16312423423432",
        //         "liqRiskRatio": "1.01",
        //         "totalAssets": "1242.34",
        //         "totalDebt": "1100",
        //         "LiqFee": "1.2",
        //         "uTime": "1692690126000"
        //         "cTime": "1653453245342"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(liquidation, "symbol");
        Object timestamp = this.safeInteger(liquidation, "liqEndTime");
        Object liquidationFee = this.safeString2(liquidation, "LiqFee", "liqFee");
        Object totalDebt = this.safeString(liquidation, "totalDebt");
        Object quoteValueString = Precise.stringAdd(liquidationFee, totalDebt);
        return this.safeLiquidation(new java.util.HashMap<String, Object>() {{
            put( "info", liquidation );
            put( "symbol", BitgetCore.this.safeSymbol(marketId, market) );
            put( "contracts", null );
            put( "contractSize", null );
            put( "price", null );
            put( "baseValue", null );
            put( "quoteValue", BitgetCore.this.parseNumber(quoteValueString) );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
        }});
    }

